import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

changes = []
unchanged = []

for bp, ap in zip(baseline['projects'], after['projects']):
    proj = bp['path'].split('/')[-1]
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        fw = bf['framework']
        b_pkgs = {p['id']: p['resolvedVersion'] for p in bf['topLevelPackages']}
        a_pkgs = {p['id']: p['resolvedVersion'] for p in af['topLevelPackages']}
        all_pkgs = set(b_pkgs.keys()) | set(a_pkgs.keys())
        for pkg in sorted(all_pkgs):
            bv = b_pkgs.get(pkg)
            av = a_pkgs.get(pkg)
            if bv != av:
                changes.append((proj, fw, pkg, bv or '(none)', av or '(none)'))
            else:
                unchanged.append((proj, fw, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('  None')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===' )
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]} {u[3]}')
"

